const logs = $input.item.json.logs || [];
const destLat = $node["Supabase Dispute Webhook"].json.body.record.dest_lat;
const destLng = $node["Supabase Dispute Webhook"].json.body.record.dest_lng;
const otpVerified = $node["Supabase Dispute Webhook"].json.body.record.otp_verified || false;

// Calculate geofence distance
function getDistanceKm(lat1, lon1, lat2, lon2) {
  const R = 6371; // Radius of the earth in km
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = 
    Math.sin(dLat/2) * Math.sin(dLat/2) +
    Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) *
    Math.sin(dLon/2) * Math.sin(dLon/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  return R * c; // Distance in km
}

let reachedDestination = false;
for (const log of logs) {
  if (log.location && log.location.coordinates) {
    const [lng, lat] = log.location.coordinates;
    const dist = getDistanceKm(lat, lng, destLat, destLng);
    if (dist <= 0.5) { // 500 meters geofence
      reachedDestination = true;
      break;
    }
  }
}

return {
  reached_destination: reachedDestination,
  otp_verified: otpVerified,
  auto_resolvable: reachedDestination && otpVerified,
  evidence_packaged: {
    log_count: logs.length,
    reached_destination: reachedDestination,
    otp_verified: otpVerified
  }
};
